Schema::create('trial_sessions', function (Blueprint $t) {
    $t->string('id', 64)->primary();
    $t->workspaceable();
    $t->invitable();       // register-only; also serves as a doc anchor for what invites this row supports
    $t->string('name');
    $t->timestamps();
});

// The `invitable()` macro simply annotates the migration for the CI cross-check; it does not add columns.
// The invitations table already handles the polymorphic (target_type, target_id) tuple.

// Registration in the consumer module's service provider:
public function boot(InvitationTargetRegistry $registry): void
{
    $registry->registerTargetType(
        key: 'trial_session',
        class: TrialSession::class,
        acceptHandler: TrialSessionInvitationAcceptHandler::class,
    );
}
